import React, { useEffect, useState } from "react";
import axios from "axios";
import "bootstrap/dist/css/bootstrap.min.css";

export default function VentasPage() {
  const [clientes, setClientes] = useState([]);
  const [productos, setProductos] = useState([]);
  const [clienteSeleccionado, setClienteSeleccionado] = useState(null);
  const [busquedaCliente, setBusquedaCliente] = useState("");
  const [nuevoCliente, setNuevoCliente] = useState({ nombre: "", correo: "", telefono: "" });
  const [carrito, setCarrito] = useState([]);
  const [busquedaProducto, setBusquedaProducto] = useState("");

  // 🧾 Cargar clientes y productos
  useEffect(() => {
    obtenerClientes();
    obtenerProductos();
  }, []);

  const obtenerClientes = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/clientes");
      setClientes(res.data);
    } catch (error) {
      console.error("❌ Error al obtener clientes:", error);
    }
  };

  const obtenerProductos = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/productos");
      setProductos(res.data);
    } catch (error) {
      console.error("❌ Error al obtener productos:", error);
    }
  };

  // 🧍 Buscar cliente
const clientesFiltrados = clientes.filter((c) =>
  (c.Nombre || c.nombre || "").toLowerCase().includes(busquedaCliente.toLowerCase())
);



  // 🧺 Buscar producto
 const productosFiltrados = productos.filter((p) =>
  (p.nombre || "").toLowerCase().includes(busquedaProducto.toLowerCase())
);

  // ➕ Agregar producto al carrito
  const agregarAlCarrito = (producto) => {
    if (producto.stock <= 0) {
      alert("❌ No hay stock disponible");
      return;
    }

    const existe = carrito.find((item) => item.id === producto.id);
    if (existe) {
      alert("⚠️ El producto ya está en el carrito");
      return;
    }

    setCarrito([...carrito, { ...producto, cantidad: 1 }]);
  };

  // 🔁 Cambiar cantidad
  const cambiarCantidad = (id, cantidad) => {
    setCarrito((prev) =>
      prev.map((item) =>
        item.id === id ? { ...item, cantidad: Number(cantidad) } : item
      )
    );
  };

  // ❌ Quitar producto
  const eliminarDelCarrito = (id) => {
    setCarrito((prev) => prev.filter((item) => item.id !== id));
  };

  // 💲 Calcular total
  const total = carrito.reduce(
    (acc, item) => acc + item.precio * item.cantidad,
    0
  );

  // 💾 Registrar venta
  const registrarVenta = async () => {
    if (!clienteSeleccionado && !nuevoCliente.nombre) {
      alert("Debes seleccionar o agregar un cliente");
      return;
    }
    if (carrito.length === 0) {
      alert("Agrega al menos un producto");
      return;
    }

    try {
      let clienteID = clienteSeleccionado?.ClienteID;

      // Si el cliente es nuevo, crearlo primero
      if (!clienteID) {
        const resCliente = await axios.post("http://localhost:5000/api/clientes", nuevoCliente);
        clienteID = resCliente.data.ClienteID;
      }

      // Registrar venta
      const venta = {
        clienteID,
        productos: carrito.map((item) => ({
          productoID: item.id,
          cantidad: item.cantidad,
          subtotal: item.precio * item.cantidad,
        })),
        total,
      };

      await axios.post("http://localhost:5000/api/ventas", venta);

      alert("✅ Venta registrada exitosamente");
      setCarrito([]);
      setClienteSeleccionado(null);
      setNuevoCliente({ nombre: "", correo: "", telefono: "" });
      setBusquedaCliente("");
      obtenerProductos(); // actualizar stock
    } catch (error) {
      console.error("❌ Error al registrar venta:", error);
      alert("Error al registrar la venta");
    }
  };

  return (
    <div className="container mt-4">
      <h2 className="fw-bold text-center mb-4">🛒 Nueva Venta</h2>

      {/* --- SECCIÓN CLIENTE --- */}
      <div className="card shadow-sm mb-4">
        <div className="card-header bg-primary text-white fw-bold">Cliente</div>
        <div className="card-body">
          <div className="row g-3 align-items-center">
            <div className="col-md-6">
              <input
                type="text"
                className="form-control"
                placeholder="Buscar cliente por nombre..."
                value={busquedaCliente}
                onChange={(e) => setBusquedaCliente(e.target.value)}
              />
              {busquedaCliente && clientesFiltrados.length > 0 && (
                <ul className="list-group position-absolute w-50 mt-1">
                  {clientesFiltrados.map((c) => (
                    <li
                      key={c.ClienteID}
                      className="list-group-item list-group-item-action"
                      style={{ cursor: "pointer" }}
                      onClick={() => {
                        setClienteSeleccionado(c);
                        setBusquedaCliente("");
                      }}
                    >
                      {c.Nombre} {c.Apellido} - {c.Correo}
                    </li>
                  ))}
                </ul>
              )}
            </div>

            <div className="col-md-6">
              {clienteSeleccionado ? (
                <div className="alert alert-success mb-0">
                  Cliente seleccionado:{" "}
                  <strong>
                    {clienteSeleccionado.Nombre} {clienteSeleccionado.Apellido}
                  </strong>
                  <button
                    className="btn btn-sm btn-outline-danger ms-3"
                    onClick={() => setClienteSeleccionado(null)}
                  >
                    Cambiar
                  </button>
                </div>
              ) : (
                <div>
                  <p className="text-muted">O agrega un nuevo cliente:</p>
                  <div className="d-flex gap-2">
                    <input
                      type="text"
                      className="form-control"
                      placeholder="Nombre"
                      value={nuevoCliente.nombre}
                      onChange={(e) =>
                        setNuevoCliente({ ...nuevoCliente, nombre: e.target.value })
                      }
                    />
                    <input
                      type="email"
                      className="form-control"
                      placeholder="Correo"
                      value={nuevoCliente.correo}
                      onChange={(e) =>
                        setNuevoCliente({ ...nuevoCliente, correo: e.target.value })
                      }
                    />
                    <input
                      type="text"
                      className="form-control"
                      placeholder="Teléfono"
                      value={nuevoCliente.telefono}
                      onChange={(e) =>
                        setNuevoCliente({ ...nuevoCliente, telefono: e.target.value })
                      }
                    />
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* --- SECCIÓN PRODUCTOS --- */}
      <div className="card shadow-sm mb-4">
        <div className="card-header bg-dark text-white fw-bold">Productos</div>
        <div className="card-body">
          <div className="mb-3">
            <input
              type="text"
              className="form-control"
              placeholder="Buscar producto..."
              value={busquedaProducto}
              onChange={(e) => setBusquedaProducto(e.target.value)}
            />
          </div>

          <div className="row">
            {productosFiltrados.map((p) => (
              <div key={p.id} className="col-md-3 mb-3">
                <div className="card h-100 text-center shadow-sm">
                  <div className="card-body">
                    <h6>{p.nombre}</h6>
                    <p className="text-muted mb-1">Precio: ${p.precio}</p>
                    <p className="text-muted">Stock: {p.stock}</p>
                    <button
                      className="btn btn-sm btn-primary"
                      onClick={() => agregarAlCarrito(p)}
                    >
                      ➕ Agregar
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* --- SECCIÓN CARRITO --- */}
      <div className="card shadow-sm mb-5">
        <div className="card-header bg-success text-white fw-bold">
          Carrito de Venta
        </div>
        <div className="card-body">
          {carrito.length === 0 ? (
            <p className="text-center text-muted">No hay productos en el carrito.</p>
          ) : (
            <table className="table table-bordered text-center align-middle">
              <thead className="table-light">
                <tr>
                  <th>Producto</th>
                  <th>Precio</th>
                  <th>Cantidad</th>
                  <th>Subtotal</th>
                  <th>Acción</th>
                </tr>
              </thead>
              <tbody>
                {carrito.map((item) => (
                  <tr key={item.id}>
                    <td>{item.nombre}</td>
                    <td>${item.precio}</td>
                    <td>
                      <input
                        type="number"
                        min="1"
                        max={item.stock}
                        className="form-control text-center"
                        value={item.cantidad}
                        onChange={(e) => cambiarCantidad(item.id, e.target.value)}
                      />
                    </td>
                    <td>${(item.precio * item.cantidad).toFixed(2)}</td>
                    <td>
                      <button
                        className="btn btn-sm btn-danger"
                        onClick={() => eliminarDelCarrito(item.id)}
                      >
                        🗑️
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}

          <div className="d-flex justify-content-between align-items-center mt-3">
            <h5 className="fw-bold">Total: ${total.toFixed(2)}</h5>
            <button className="btn btn-success" onClick={registrarVenta}>
              💾 Registrar Venta
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}
